/// <https://drafts.csswg.org/cssom-view/#document-run-the-scroll-steps>
pub(crate) fn run_the_scroll_steps(&self, can_gc: CanGc) {
    // Step 1.
    // > Run the steps to dispatch pending scrollsnapchanging events for doc.
    // TODO(#7673): Implement scroll snapping

    // Step 2
    // > For each item target in doc's pending scroll event targets, in the order they
    // > were added to the list, run these substeps:
    // Step 3.
    // > Empty doc's pending scroll event targets.
    // Since the scroll event callback could trigger another scroll event, we are taking all of the
    // current scroll event to avoid borrow checking error.
    rooted_vec!(let notify_list <- self.pending_scroll_event_targets.take().into_iter());
    for target in notify_list.iter() {
        if target.downcast::<Document>().is_some() {
            // Step 2.1
            // > If target is a Document, fire an event named scroll that bubbles at target.
            target.fire_bubbling_event(Atom::from("scroll"), can_gc);
        } else if target.downcast::<Element>().is_some() {
            // Step 2.2
            // > Otherwise, fire an event named scroll at target.
            target.fire_event(Atom::from("scroll"), can_gc);
        }
    }

    // Schedule scrollend events for any targets that received scroll events
    // We need to do this after firing scroll events
    if !notify_list.is_empty() {
        // Move the scroll event targets to pending_scrollend_targets for debouncing
        for target in notify_list.iter() {
            self.pending_scrollend_targets
                .borrow_mut()
                .push(Dom::from_ref(target.as_ref()));
        }
        self.schedule_scrollend_event(can_gc);
    }

    // Step 4.
    // > Run the steps to dispatch pending scrollsnapchange events for doc.
    // TODO(#7673): Implement scroll snapping
}

/// Schedule a scrollend event to fire after a debounce delay.
/// This implements debouncing so that if multiple scrolls happen in quick succession,
/// only one scrollend event fires after the last scroll.
fn schedule_scrollend_event(&self, can_gc: CanGc) {
    // Cancel any existing scrollend timer
    if let Some(handle) = self.scrollend_timer.take() {
        self.window().as_global_scope().unschedule_callback(handle);
    }

    // Schedule a new scrollend timer with a 150ms debounce delay
    let callback = crate::timers::OneshotTimerCallback::ScrollendEvent(ScrollendCallback {
        document: DomRoot::from_ref(self),
    });
    let duration = std::time::Duration::from_millis(150);
    let handle = self.window()
        .as_global_scope()
        .schedule_callback(callback, duration);
    self.scrollend_timer.set(Some(handle));
}

